-- Enrichment marathon batch: Cider, Cinelerra-CV, Cinnamon, CipherCloud, cirun.io, Clapper, Clappia, ClassDojo

-- ── Cider ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cider is a free, open-source, cross-platform client for Apple Music built with Electron and Vue.js by the volunteer Cider Collective. It gives Windows, macOS, Linux, and Android users a customizable, resource-conscious alternative to Apple's official Music app while streaming through an existing Apple Music subscription via Apple's MusicKit APIs.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source, with optional pay-what-you-want support tiers on itch.io and Patreon$q$, pricing_model),
  starting_price = COALESCE($q$Free (an active Apple Music subscription is required to stream content)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$Volunteer-run open-source collective, not a registered company; contributor headcount not publicly disclosed$q$, company_size),
  headquarters = COALESCE($q$Distributed open-source project with no fixed corporate headquarters$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Cider Review 2026: Free Open-Source Apple Music Client$q$, seo_title),
  seo_meta_description = COALESCE($q$Cider is a free, open-source Apple Music client for Windows, macOS, Linux, and Android. Explore features, pricing, pros, cons, and FAQs for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Cider is a free, open-source desktop and mobile client for Apple Music, developed by a volunteer group of developers known as the Cider Collective. The project began as an indie effort called Apple Music Electron, aiming to bring Apple's streaming service to platforms Apple does not officially support, and was later rebranded as Cider. Cider 1, the original release, was built using Electron.js, Vue.js 2, and Webpack, and its source code was published as open source, allowing anyone to inspect, modify, or self-host the client. Cider connects to a user's existing Apple Music account through Apple's official MusicKit JS and MusicKit APIs, meaning it does not bypass Apple's licensing or DRM; a paid Apple Music subscription is still required to stream music, since Apple Music has no free tier. The application is available for Windows, macOS, Linux, and Android, filling a long-standing gap for Apple Music on Linux desktops, a platform Apple has never officially supported. Cider differentiates itself from Apple's stock Music app through deep customization: users can apply community themes, adjust the interface layout, and extend functionality with plugins. Notable built-in features include Discord Rich Presence integration so friends can see what a user is currently listening to, Last.fm scrobbling for tracking listening history, an audio equalizer with presets, an audio spatialization and enhancement engine sometimes referred to as an Adrenaline Processor, offline playback for downloaded songs, albums, and playlists, and support for Apple Music Sing, Apple's real-time lyrics and karaoke feature. A significant shift occurred with Cider 2, a from-scratch rewrite that moved to a high-performance custom backend built in Rust for lower memory usage and faster startup times; unlike Cider 1, Cider 2 is closed-source and proprietary, and as of 2026 remains in early access, distributed through the Cider Collective's own website, itch.io, the Microsoft Store, and other channels. This licensing split is an important distinction for anyone evaluating Cider for its open-source credentials: Cider 1's codebase remains publicly available on GitHub under the Cider Collective organization, while Cider 2's binaries are free to use but not open source. The Cider Collective funds ongoing development through optional, pay-what-you-want contributions on itch.io (with a suggested price point around 3.49 dollars) and through Patreon, but the application itself is not gated behind a paywall. Because Cider relies on Apple's official APIs rather than reverse-engineered access, it is generally more stable across Apple Music catalog and metadata changes than unofficial scraping-based clients, though it remains dependent on Apple continuing to expose MusicKit endpoints to third parties. Cider is best understood as a community-built shell around Apple Music's official web technologies, prized by Linux users, power users who want scriptable and skinnable music players, and anyone who finds Apple's first-party Music app on Windows underdeveloped. It should not be confused with unrelated products that also use the word cider, such as beverage brands or other software projects; this Cider is specifically the Apple Music player maintained by the Cider Collective.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '310dfd9e-3e2a-4361-aa51-f37142ec1fda';

