-- ── Cinelerra-CV ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cinelerra-CV, short for Cinelerra Community Version, is a free and open-source non-linear video editor and compositor for Linux. It was forked in 2003 from Heroine Virtual's original Cinelerra codebase by community developers who wanted a version built with standard shared system libraries rather than bundled dependencies.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source (GPL-licensed)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2003, founded_year),
  company_size = COALESCE($q$Volunteer open-source community project (the Cinelerra-CV Team); not a commercial company$q$, company_size),
  headquarters = COALESCE($q$Not applicable, distributed open-source project with no corporate headquarters$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Cinelerra-CV: Free Open-Source Linux Video Editor Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$Cinelerra-CV is a free, open-source non-linear video editor for Linux. Learn its history, features, pros, cons, and how it differs from other forks.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Cinelerra-CV, where CV stands for Community Version, is a free and open-source non-linear video editing and compositing application for Linux. It traces its origins to Cinelerra, an advanced NLE originally developed by Heroine Virtual, a small studio led by Adam Williams. Heroine Virtual's Cinelerra gained notice as one of the first video editors rewritten for 64-bit processors, being adapted for the AMD Opteron architecture in 2003 and presented at SIGGRAPH 2004. That same year, in April 2003, a group within the Cinelerra user community decided to maintain an independent copy of the software's source code, giving rise to Cinelerra-CV. The relationship between Heroine Virtual and the Cinelerra-CV community has generally been described as cooperative rather than adversarial, with Heroine Virtual occasionally participating in Cinelerra-CV mailing list discussions and incorporating some community-driven changes back into its own line. The key technical distinction driving the fork is dependency management: Cinelerra-CV is built to compile against libraries already installed as shared system libraries on a user's Linux distribution, whereas Heroine Virtual's official branch, sometimes called Cinelerra-HV, bundles many of its own library versions directly into its custom build process. This makes Cinelerra-CV easier to package and maintain for Linux distributions and system integrators, even though it is derived from the same original codebase. Cinelerra-CV should not be confused with the other major Cinelerra descendants that emerged later: Cinelerra-GG Infinity, maintained by Good Guy (William Morrow), which has become one of the more actively developed forks with modern hardware acceleration support, and Lumiera, an ambitious from-scratch redesign inspired by Cinelerra's editing model that never reached a stable production release. As a non-linear editor, Cinelerra-CV supports timeline-based editing across multiple video and audio tracks, track-based compositing operations such as keying and mattes, a built-in title generator, a library of video and audio effects, and keyframe automation for animating effect parameters over time. It is aimed at users who need professional-grade editing and compositing capabilities on Linux without relying on proprietary software, and it has historically been popular among Linux enthusiasts, hobbyist filmmakers, and technically inclined video professionals willing to work with a less polished, community-maintained interface in exchange for full source access and no licensing cost. Cinelerra-CV's official code repository has been hosted on GitHub under the Cinelerra-CV Team organization since around 2020, when the project's official site and repository were refreshed, and it continues to receive maintenance updates including bug fixes and compiler compatibility improvements from a small group of volunteer contributors. Because development activity is comparatively modest relative to more actively funded commercial editors, users evaluating Cinelerra-CV in 2026 should expect an interface and workflow that reflects its long history rather than a modern redesign, and should weigh it against sibling forks like Cinelerra-GG if broader hardware acceleration or more frequent updates are a priority.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5f4c56e8-3617-49c1-a970-6222e4223356';

