-- ── CipherCloud ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$CipherCloud was a cloud security company that built a cloud access security broker, or CASB, platform providing encryption, tokenization, data loss prevention, and adaptive access controls for enterprise cloud applications such as Salesforce, Office 365, and Google Drive. Founded in 2010 and headquartered in San Jose, California, CipherCloud was acquired by Lookout in March 2021, and its CASB technology line was later sold by Lookout to Fortra in May 2025.$q$, short_description),
  pricing_model = COALESCE($q$Enterprise licensing, historically quoted per organization; CipherCloud is no longer sold as a standalone product$q$, pricing_model),
  starting_price = COALESCE($q$Custom enterprise pricing (product line discontinued under the CipherCloud name following its 2021 acquisition and 2025 resale)$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$Formerly a mid-sized cybersecurity company; now absorbed into Fortra's product portfolio following the 2025 divestiture from Lookout$q$, company_size),
  headquarters = COALESCE($q$Originally San Jose, California, United States, with former regional offices in London, England and Australia$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$CipherCloud: CASB History, Features, and Current Status$q$, seo_title),
  seo_meta_description = COALESCE($q$CipherCloud was a cloud access security broker acquired by Lookout in 2021 and later sold to Fortra. Learn its history, features, and current status.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CipherCloud was an American cybersecurity company that pioneered cloud access security broker, or CASB, technology, founded in 2010 by Pravin Kothari, who had previously co-founded the security company ArcSight. Headquartered in San Jose, California, CipherCloud launched its first commercial product in February 2011, initially focused on securing Salesforce.com deployments through encryption and tokenization applied before sensitive data left an organization's control. The company expanded quickly, adding support for Amazon Web Services environments later in 2011, releasing a Gmail security service in June 2012, and extending coverage to Force.com, Chatter, and Microsoft Office 365 by September 2012. CipherCloud's growth was backed by significant venture funding, including a 30 million dollar round led by Andreessen Horowitz and Index Ventures closed in December 2012, the same month the company opened a European headquarters in London. It later added an Australian headquarters in 2013 and made an acquisition of its own, purchasing CloudUp Networks in January 2014, followed by the launch of CipherCloud Cloud Discovery in April 2014, a product designed to analyze firewall and proxy logs to detect unsanctioned Shadow IT cloud application usage and assess associated risk. Over the following years, CipherCloud's flagship offering evolved into a product generally marketed as CipherCloud CASB Plus, which bundled data loss prevention, in-motion and at-rest encryption, digital rights management, and adaptive, risk-based access controls into a single platform. The platform was built to protect data across more than 40 major cloud applications, and included capabilities such as continuous activity monitoring across multiple cloud services with anomaly detection, real-time malware scanning and quarantine to stop threats from entering networks through cloud channels, and compliance-oriented reporting and auditing designed to help organizations meet frameworks like GDPR, HIPAA, and PCI DSS. In March 2021, CipherCloud was acquired by Lookout, a mobile and endpoint security company, in a deal intended to combine Lookout's endpoint security with CipherCloud's cloud-native SASE-oriented technologies, spanning CASB, zero-trust network access, secure web gateway, and data loss prevention, into a single end-to-end security platform covering the path from endpoint to cloud. Financial terms of the acquisition were not disclosed, and CipherCloud's founder and CEO Pravin Kothari joined Lookout as an executive vice president overseeing product and SASE strategy. Following the acquisition, the CipherCloud brand was gradually folded into Lookout's product naming, with offerings referred to as Lookout CASB or Lookout Secure Cloud Access. In a further ownership change, Lookout sold the assets of its cloud security business, built on the former CipherCloud technology, to Fortra in May 2025. As a result, CipherCloud as an independent, standalone brand no longer exists in the market as of 2026; its technology and customer base now operate under Fortra's ownership, while the original CipherCloud company name is primarily of historical and reference interest for understanding the lineage of modern CASB and cloud data protection products. Anyone researching CipherCloud today is most likely encountering references to its historical product capabilities, its acquisition history, or comparisons made in CASB market analyses that still cite it as an early and influential player in the category.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6e2cffb0-5e91-4ff6-82cc-3ff414a58b5b';

