-- ── cirun.io ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$cirun.io is a CI/CD infrastructure platform that provisions self-hosted runners for GitHub Actions and GitLab CI on demand, spinning up ephemeral virtual machines on a user's own cloud account such as AWS, GCP, Azure, or Oracle Cloud. It is built and maintained by Aktech Labs, a small engineering consultancy, and is free for open-source projects.$q$, short_description),
  pricing_model = COALESCE($q$Freemium subscription based on the number of private repositories connected; free for public and open-source repositories$q$, pricing_model),
  starting_price = COALESCE($q$Free for open source; paid plans start at 29 dollars per month for up to 3 private repositories$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$Small team operated by Aktech Labs; exact headcount not publicly disclosed$q$, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$cirun.io Review 2026: Self-Hosted CI Runners on Your Cloud$q$, seo_title),
  seo_meta_description = COALESCE($q$cirun.io provisions self-hosted GitHub Actions and GitLab CI runners on your own cloud account. See pricing, features, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$cirun.io is a continuous integration and continuous delivery infrastructure tool that solves a specific, common problem for engineering teams: GitHub Actions and GitLab CI's own hosted runners are convenient but can become slow or expensive for larger builds, especially workloads that need more CPU, memory, GPU access, or ARM architecture support than the vendor-hosted default runners provide. Rather than operating its own fleet of build machines and billing per minute the way traditional hosted CI providers do, cirun.io orchestrates self-hosted runners on infrastructure the customer already owns and pays for directly, including Amazon Web Services, Google Cloud Platform, Microsoft Azure, Oracle Cloud, DigitalOcean, and on-premise OpenStack environments. Teams define runner requirements, such as instance type, region, and cloud provider, in a repository configuration file named dot-cirun-dot-yml, and cirun.io handles provisioning an ephemeral virtual machine for each CI job, registering it as a runner, and tearing it down automatically once the job completes. Because the underlying compute is billed directly by the cloud provider rather than marked up by cirun.io, organizations can access spot or reserved pricing, custom machine images, and specialized hardware like GPUs that are difficult or impossible to get from GitHub's or GitLab's own hosted runner tiers, while cirun.io itself charges only for the orchestration layer. cirun.io is developed by Aktech Labs, a boutique engineering consultancy based in London, United Kingdom, that works across web development, machine learning, big data, and operations research; the product appears to have emerged from Aktech Labs' own infrastructure needs before becoming a public offering, with visible activity dating back to around 2021. The GitHub account associated with the project is maintained under the AktechLabs organization, and Amit Kumar is publicly associated with the project's GitHub presence. cirun.io positions itself as sustainable and independently operated rather than venture-funded, describing itself as financially self-sufficient and growing through customer revenue, which the company frames as allowing it to prioritize user and developer community needs over investor pressure. Pricing follows a tiered subscription model gated by the number of connected private repositories: an Open Source tier is free and includes unlimited public repositories, unlimited runners, and access to Arm, GPU, and all supported cloud providers; a Startup tier at 29 dollars per month supports up to 3 private repositories with Slack and email support; a Business tier at 79 dollars per month supports up to 10 private repositories; an Enterprise tier at 99 dollars per month supports up to 20 private repositories; and an Enterprise Plus tier at 499 dollars per month supports up to 100 private repositories with premium support. In every tier, the actual compute costs for the provisioned virtual machines are billed separately by the customer's chosen cloud provider, not by cirun.io. This model makes cirun.io most attractive to teams already running meaningful workloads on cloud infrastructure who want tighter cost control, custom hardware access such as GPU-enabled runners for machine learning pipelines, or compliance requirements that mandate builds run inside their own cloud account rather than a third party's shared infrastructure, as opposed to smaller teams or hobby projects for whom GitHub's or GitLab's default hosted runners remain simpler and sufficient.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '41d1b5f6-c8db-4613-a01f-279f3c9c767a';

