-- ── Clapper ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Clapper is a free, open-source media player for the GNOME desktop, built with GTK4 and powered by the GStreamer multimedia framework. Created primarily by developer Rafal Dziegiel, known online as Rafostar, it offers a minimalist, modern interface with windowed, floating, and fullscreen viewing modes.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$Independent open-source hobby project, primarily developed by a single maintainer with community contributions; not a company$q$, company_size),
  headquarters = COALESCE($q$Not applicable, independent open-source project with no corporate headquarters$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Clapper Media Player: Free GNOME Video Player Guide 2026$q$, seo_title),
  seo_meta_description = COALESCE($q$Clapper is a free, open-source GTK4 media player for GNOME built on GStreamer. See features, pros, cons, and FAQs for this modern Linux video player.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Clapper is a free, open-source media player built specifically for the GNOME desktop environment, using the GTK4 toolkit for its interface and the GStreamer multimedia framework as its playback backend, with OpenGL used for rendering. The project is coded primarily in GJS, GNOME's JavaScript bindings, and is developed largely by a single developer, Rafal Dzieciol known by the handle Rafostar, who maintains the project mainly as a personal, hobby-driven effort in his free time, which the project itself acknowledges results in steady rather than especially fast development pace. Clapper's visual identity departs from conventional media player design by omitting a traditional upper title bar in favor of auto-hiding controls, including a preferences menu, a mode switcher, and window control buttons that appear only when needed, giving the interface an unusually clean, minimalist look when paused or during full-screen playback. The player offers three distinct viewing modes: a standard Windowed Mode for normal desktop use, a Floating Mode that keeps a resizable video window on top of other applications for multitasking, and a Fullscreen Mode for distraction-free viewing. Under the hood, Clapper relies on GStreamer for decoding and playback, which gives it broad codec and container format support consistent with whatever GStreamer plugins are installed on the host system, and it renders video using OpenGL for smooth, hardware-accelerated playback on both Intel and AMD graphics hardware. It supports both the older Xorg display server and the newer Wayland protocol, which matters for GNOME users since GNOME's own shell has been Wayland-first for years. Practical features include Media Player Remote Interfacing Specification, or MPRIS, support, which lets Clapper integrate with GNOME's system media controls and other MPRIS-aware desktop tools; configurable repeat options for looping playback; a full set of keyboard shortcuts for hands-off control; subtitle support with adjustable font and audio offset settings for fine-tuning synchronization; and support for streaming sources such as YouTube in addition to local files. Clapper is distributed primarily through Flatpak, the cross-distribution Linux packaging format, which is the officially recommended installation method and ensures consistent behavior across different Linux distributions regardless of their underlying package management systems; it is also available through the Arch User Repository for Arch and Manjaro users and is packaged in repositories such as Fedora's. The project has been associated with GNOME's broader application ecosystem and is commonly listed among recommended GNOME-native media players, reflecting its adherence to GNOME's human interface guidelines and its use of GNOME platform technologies, though as an independently maintained project it does not carry the backing of a company or foundation beyond the volunteer GNOME infrastructure it builds upon. Because Clapper is free, open source, and maintained without a commercial entity behind it, there is no pricing model, subscription, or paid tier to evaluate; its ongoing availability depends on continued volunteer maintenance by its developer and contributors rather than a business roadmap. It is best suited to GNOME desktop users who want a native-feeling, visually minimal video player that integrates cleanly with GNOME's design language, as opposed to users who need advanced editing, transcoding, or professional media management features, which fall outside Clapper's intentionally focused scope as a playback-first application.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0f3be02e-1282-4521-8595-0409429ece35';

