-- ── ClassDojo ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$ClassDojo is a widely used classroom communication app connecting K-12 teachers, students, and families through messaging, behavior and skill tracking, photo and video updates, and student portfolios. Founded in 2011 and headquartered in San Francisco, California, it reports usage in a large majority of United States schools and offers an optional paid subscription called ClassDojo Plus for additional family-facing features.$q$, short_description),
  pricing_model = COALESCE($q$Freemium: free for teachers and schools, with an optional paid subscription for families$q$, pricing_model),
  starting_price = COALESCE($q$Free for teachers and schools; ClassDojo Plus is 4.99 dollars per month or 59.99 dollars per year for families$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$Approximately 300 employees, based on 2023 reporting$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Spanish$q$, $q$and 190 plus additional languages supported through automatic message translation$q$]::text[],
  seo_title = COALESCE($q$ClassDojo Review 2026: Classroom App Features and Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$ClassDojo connects teachers, students, and families through messaging and behavior tracking. See features, pricing, pros, cons, and FAQs for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$ClassDojo is a classroom communication and engagement platform founded in 2011 by Sam Chaudhary and Liam Don, headquartered in San Francisco, California. The company built its product around a simple premise: give teachers, students, and families a shared, real-time digital space to communicate and track classroom life, replacing fragmented paper notes, phone calls, and disconnected email threads. ClassDojo has grown into one of the most widely adopted education technology products in the United States, with the company reporting usage in the large majority of American K-12 schools, alongside significant international adoption. The platform's core, free offering centers on several connected features. A points-based behavior and skills tracking system lets teachers award or subtract points tied to specific behaviors or character skills, giving students real-time feedback and giving families visibility into classroom conduct. Class Story functions as a private, secure photo and video feed where teachers can share moments from the classroom with parents, similar in spirit to a social media feed but restricted to a specific class's families. Student Portfolios let students themselves contribute by uploading photos, videos, and work samples documenting their own learning. Underpinning all of this is a messaging system that lets teachers and families communicate directly, with messages automatically translated into more than 190 languages, a feature aimed at making the platform accessible to non-English-speaking families, which is particularly significant given the linguistic diversity of many American school districts. ClassDojo's business model is freemium: the core app, including messaging, points tracking, Class Story, and portfolios, is free for teachers, schools, and families to use. Revenue comes primarily from ClassDojo Plus, an optional premium subscription marketed to parents and families rather than schools, which unlocks additional features for tracking and engaging with a child's school experience; ClassDojo Plus is offered after a seven-day free trial at 4.99 dollars per month or 59.99 dollars per year. The company has raised approximately 221 million dollars in venture funding across multiple rounds since its founding, including a 1.6 million dollar seed round in January 2012, an 8.5 million dollar Series A in April 2013, a 21 million dollar Series B in April 2016, a 35 million dollar Series C in February 2019, and a 125 million dollar Series D in July 2022, with investors including General Catalyst and Y Combinator, the startup accelerator ClassDojo went through early in its history. As of the most recent independent reporting available, the company was valued at approximately 1.25 to 1.3 billion dollars and reported annual recurring revenue in the range of roughly 52 million dollars, with a team of around 301 employees as of 2023 figures. ClassDojo's growth trajectory reflects a broader shift in education technology toward tools that center family engagement alongside classroom management, rather than treating parent communication as a secondary feature bolted onto a gradebook or learning management system. Because the core product remains free for teachers and schools, ClassDojo has achieved widespread organic adoption driven largely by individual teachers signing up their classrooms, a bottom-up growth pattern common among successful education technology products, rather than relying solely on top-down district-wide procurement deals, although the company has also pursued official school and district partnerships over time. For anyone evaluating ClassDojo in 2026, the key facts to know are that it remains free for classroom use, monetizes primarily through an optional family subscription, and continues to be one of the most recognized names in K-12 classroom communication technology in the United States and internationally.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '78f9c872-baf1-45b9-a0fe-d001e187a972';

